(async function () {
  if (typeof document === "undefined") {
    return;
  }

  // Guard against multiple executions
  if (window.__prismjsLoaderInitialized) {
    return;
  }
  window.__prismjsLoaderInitialized = true;

  const BASE_URL = "https://cdn.jsdelivr.net/gh/PrismJS/prism@1.30.0";
  const ALL_THEMES = [
    "prism",
    "prism-coy",
    "prism-dark",
    "prism-funky",
    "prism-okaidia",
    "prism-solarizedlight",
    "prism-tomorrow",
    "prism-twilight",
  ];
  const DEFAULT_THEME = ALL_THEMES[0];

  /**
   * Waits for a condition to be met within a timeout period.
   */
  function waitForCondition(condition, timeout = 15000) {
    return new Promise((resolve, reject) => {
      // Check immediately
      if (condition()) {
        resolve();
        return;
      }

      const startTime = Date.now();
      const interval = setInterval(() => {
        if (condition()) {
          clearInterval(interval);
          resolve();
        } else if (Date.now() - startTime > timeout) {
          clearInterval(interval);
          reject(new Error("Prism failed to load within the expected time."));
        }
      }, 50);
    });
  }

  /**
   * Extracts the theme name and mode (dark or light) from a given class name.
   *
   * @param {string} className - The class name string to parse.
   * @returns {{ name: string, forDarkMode: boolean } | null} Parsed theme object or `null` if invalid.
   */
  function getThemeNameAndMode(className) {
    const raw = (className ?? "").toLowerCase();
    const name = raw.replace(/^(dark:|light:)/i, "");
    return ALL_THEMES.includes(name)
      ? { name, forDarkMode: raw.startsWith("dark:") }
      : null;
  }

  /**
   * Parses a theme string and returns theme configuration.
   *
   * @param {string} theme - The theme string to parse.
   * @returns {{ dark?: string, light?: string }} Theme configuration object.
   */
  function parseTheme(theme) {
    const themeObject = getThemeNameAndMode(theme);
    return themeObject
      ? {
          dark: themeObject.forDarkMode ? themeObject.name : undefined,
          light: themeObject.forDarkMode ? undefined : themeObject.name,
        }
      : { light: DEFAULT_THEME };
  }

  /**
   * Retrieves theme options for light and dark modes based on the current script's class list.
   *
   * @returns {{ dark?: string, light: string }} Theme options for light and dark modes.
   */
  function getThemeOptions() {
    const scriptElement = document.currentScript;
    if (scriptElement?.tagName === "SCRIPT") {
      if (scriptElement.classList.length === 0) {
        return { light: DEFAULT_THEME };
      }
      const option1 = parseTheme(scriptElement.classList[0]);
      const option2 = parseTheme(scriptElement.classList[1]);
      return {
        dark: option1.dark ?? option2.dark,
        light: option1.light ?? option2.light,
      };
    }

    return { light: DEFAULT_THEME };
  }

  /**
   * Parses the plugins parameter from the script's query string.
   *
   * @returns {string[]} Array of plugin names to load.
   */
  function getPluginsFromQueryString() {
    const scriptElement = document.currentScript;
    if (scriptElement?.tagName === "SCRIPT" && scriptElement.src) {
      try {
        const url = new URL(scriptElement.src);
        const pluginsParam = url.searchParams.get("plugins");
        if (pluginsParam) {
          return pluginsParam
            .split(",")
            .map((p) => p.trim())
            .filter(Boolean);
        }
      } catch (e) {
        console.warn("Failed to parse query string:", e);
      }
    }
    // Default plugins if none specified
    return ["autoloader"];
  }

  /**
   * Dynamically adds a script or stylesheet element to the document.
   *
   * @param {string} tagName - The type of element to create ('script' or 'link').
   * @param {string} src - The source URL for the script or stylesheet.
   * @returns {Promise<void>} Promise that resolves when the element is loaded.
   */
  function addElement({ tagName, src }) {
    return new Promise((resolve, reject) => {
      const element = document.createElement(tagName);
      element.onload = () => resolve();
      element.onerror = () =>
        reject(new Error(`Failed to load ${tagName}: ${src}`));

      if (tagName === "link") {
        element.rel = "stylesheet";
        element.href = `${BASE_URL}${src}`;
      } else if (tagName === "script") {
        element.defer = true;
        element.src = `${BASE_URL}${src}`;
      }
      document.body.appendChild(element);
    });
  }

  // Stop Prism from auto-highlighting
  window.Prism = window.Prism || {};
  window.Prism.manual = true;

  const themes = getThemeOptions();
  const isDarkMode =
    window.matchMedia &&
    window.matchMedia("(prefers-color-scheme: dark)").matches;
  const requestedPlugins = []; // getPluginsFromQueryString();

  // Plugin CSS dependencies
  const pluginCssDependencies = {
    "line-numbers": "/plugins/line-numbers/prism-line-numbers.min.css",
    "line-highlight": "/plugins/line-highlight/prism-line-highlight.min.css",
    toolbar: "/plugins/toolbar/prism-toolbar.min.css",
    "command-line": "/plugins/command-line/prism-command-line.min.css",
  };

  const coreScriptsToLoad = [
    {
      tagName: "link",
      src: `/themes/${
        isDarkMode ? themes.dark ?? themes.light : themes.light
      }.min.css`,
    },
    { tagName: "script", src: "/components/prism-core.min.js" },
  ];

  // Add CSS for plugins that need it
  requestedPlugins.forEach((plugin) => {
    if (pluginCssDependencies[plugin]) {
      coreScriptsToLoad.splice(1, 0, {
        tagName: "link",
        src: pluginCssDependencies[plugin],
      });
    }
  });

  // Build plugin scripts to load
  const pluginsToLoad = requestedPlugins.map((plugin) => ({
    tagName: "script",
    src: `/plugins/${plugin}/prism-${plugin}.min.js`,
  }));

  try {
    // Add line-numbers class if that plugin is requested
    if (requestedPlugins.includes("line-numbers")) {
      document.body.classList.add("line-numbers");
    }

    // Load core scripts sequentially (CSS first, then Prism core)
    for (const script of coreScriptsToLoad) {
      await addElement(script);
    }
    await waitForCondition(() => !!window.Prism?.filename);

    // Load plugins in parallel for better performance
    await Promise.all(pluginsToLoad.map((plugin) => addElement(plugin)));
    await waitForCondition(() => !!window.Prism?.plugins?.autoloader);

    window.Prism.highlightAll();
  } catch (error) {
    console.error("Error loading PrismJS:", error);
  }
})();
